CREATE TABLE IF NOT EXISTS "route_channel_stat_snapshots" ("id" INTEGER GENERATED BY DEFAULT AS IDENTITY NOT NULL PRIMARY KEY, "identity_key" TEXT NOT NULL, "model_pattern" TEXT NOT NULL, "account_id" INTEGER NOT NULL, "token_id" INTEGER, "oauth_route_unit_id" INTEGER, "source_model" TEXT, "success_count" INTEGER DEFAULT 0, "fail_count" INTEGER DEFAULT 0, "total_latency_ms" INTEGER DEFAULT 0, "total_cost" DOUBLE PRECISION DEFAULT 0, "total_input_tokens" INTEGER DEFAULT 0, "last_used_at" TEXT, "last_selected_at" TEXT, "last_fail_at" TEXT, "consecutive_fail_count" INTEGER NOT NULL DEFAULT 0, "cooldown_level" INTEGER NOT NULL DEFAULT 0, "cooldown_until" TEXT, "created_at" TEXT DEFAULT to_char(timezone('UTC', CURRENT_TIMESTAMP), 'YYYY-MM-DD HH24:MI:SS'), "updated_at" TEXT DEFAULT to_char(timezone('UTC', CURRENT_TIMESTAMP), 'YYYY-MM-DD HH24:MI:SS'));
CREATE UNIQUE INDEX "route_channel_stat_snapshots_identity_unique" ON "route_channel_stat_snapshots" ("identity_key");
CREATE INDEX "route_channel_stat_snapshots_account_id_idx" ON "route_channel_stat_snapshots" ("account_id");
CREATE INDEX "route_channel_stat_snapshots_model_pattern_idx" ON "route_channel_stat_snapshots" ("model_pattern");
CREATE INDEX "route_channel_stat_snapshots_oauth_route_unit_id_idx" ON "route_channel_stat_snapshots" ("oauth_route_unit_id");
CREATE INDEX "route_channel_stat_snapshots_token_id_idx" ON "route_channel_stat_snapshots" ("token_id");
